    private string          _title           = "Test-Notification";
    private string          _body            = "Das ist eine Test-Nachricht.";
    private string          _severity        = "info";
    private bool            _toCurrentUser   = true;
    private string          _extraRecipients = string.Empty;
    private HashSet<string> _channels        = ["signalr"];

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        var isAuth = await AuthService.IsAuthenticatedAsync();
        if (!isAuth) Navigation.NavigateTo("/login");
    }

    private void ToggleChannel(string channel)
    {
        if (!_channels.Remove(channel))
            _channels.Add(channel);
    }

    private async Task SendAsync()
    {
        // Client-Snackbar ist rein lokal
        if (_channels.Contains("client-snackbar"))
        {
            var sev = _severity switch
            {
                "success" => Severity.Success,
                "warning" => Severity.Warning,
                "error"   => Severity.Error,
                _         => Severity.Info
            };
            Snackbar.Add(_body, sev, opts => opts.SnackbarVariant = Variant.Filled);
        }

        var serverChannels = _channels
            .Where(c => c != "client-snackbar")
            .ToArray();

        if (serverChannels.Length > 0)
        {
            var extra = _extraRecipients
                .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .Where(s => !string.IsNullOrEmpty(s))
                .ToList();

            var token = await TokenService.GetTokenAsync();
            if (!string.IsNullOrEmpty(token))
                Http.DefaultRequestHeaders.Authorization =
                    new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", token);

            // Dev-Endpunkt: POST /api/v1/dev/send-notification
            var response = await Http.PostAsJsonAsync("api/v1/dev/send-notification", new
            {
                Title                = _title,
                Body                 = _body,
                Severity             = _severity,
                ToCurrentUser        = _toCurrentUser,
                AdditionalRecipients = extra.Count > 0 ? extra : null,
                Channels             = serverChannels
            });

            if (response.IsSuccessStatusCode)
            {
                await NotifHubService.NotifyAsync();
            }
            else
            {
                Snackbar.Add($"Server-Fehler beim Senden: HTTP {(int)response.StatusCode}", Severity.Warning);
            }
        }
    }

    private void Reset()
    {
        _title           = "Test-Notification";
        _body            = "Das ist eine Test-Nachricht.";
        _severity        = "info";
        _toCurrentUser   = true;
        _extraRecipients = string.Empty;
        _channels        = ["signalr"];
    }

